'use client'

import * as SelectPrimitive from '@radix-ui/react-select'
// Stalk UI component - requires PandaCSS setup and @stalk-ui/preset.
import { Check, ChevronDown } from 'lucide-react'
import { forwardRef } from 'react'
import { css, cx } from 'styled-system/css'
import { select as selectRecipe } from 'styled-system/recipes'

import type { ComponentPropsWithoutRef, ComponentRef, ReactNode } from 'react'

const itemEndClass = /* @__PURE__ */ css({ color: 'fg.muted', marginInlineStart: 'auto' })

export type SelectSize = (typeof selectRecipe.variantMap.size)[number]

export const SelectRoot = SelectPrimitive.Root
export const SelectGroup = SelectPrimitive.Group
export const SelectValue = SelectPrimitive.Value
export const SelectPortal = SelectPrimitive.Portal

export interface SelectTriggerProps extends ComponentPropsWithoutRef<
  typeof SelectPrimitive.Trigger
> {
  /** Stretch the trigger to fill its container; default is content-width. */
  fullWidth?: boolean
  invalid?: boolean
  size?: SelectSize
}

export const SelectTrigger = /* @__PURE__ */ forwardRef<
  ComponentRef<typeof SelectPrimitive.Trigger>,
  SelectTriggerProps
>(function SelectTrigger(
  {
    'aria-invalid': ariaInvalid,
    children,
    className,
    fullWidth = false,
    invalid = false,
    size = 'md',
    ...props
  },
  ref,
) {
  const isInvalid = invalid || ariaInvalid === true || ariaInvalid === 'true'
  const styles = selectRecipe({ fullWidth, size })

  return (
    <SelectPrimitive.Trigger
      ref={ref}
      aria-invalid={isInvalid ? true : ariaInvalid}
      className={cx(styles.trigger, className)}
      data-invalid={isInvalid ? '' : undefined}
      {...props}
    >
      {children}
      <SelectPrimitive.Icon asChild>
        <ChevronDown aria-hidden="true" height={16} width={16} />
      </SelectPrimitive.Icon>
    </SelectPrimitive.Trigger>
  )
})
export type SelectContentProps = ComponentPropsWithoutRef<typeof SelectPrimitive.Content>

export const SelectContent = /* @__PURE__ */ forwardRef<
  ComponentRef<typeof SelectPrimitive.Content>,
  SelectContentProps
>(function SelectContent({ children, className, position = 'popper', ...props }, ref) {
  const styles = /* @__PURE__ */ selectRecipe()

  return (
    <SelectPrimitive.Portal>
      <SelectPrimitive.Content
        ref={ref}
        className={cx(styles.content, className)}
        position={position}
        {...props}
      >
        <SelectPrimitive.Viewport className={styles.viewport}>{children}</SelectPrimitive.Viewport>
      </SelectPrimitive.Content>
    </SelectPrimitive.Portal>
  )
})
export interface SelectItemProps extends ComponentPropsWithoutRef<typeof SelectPrimitive.Item> {
  /** Trailing content aligned to the inline-end of the option (e.g. meta/shortcut). */
  endContent?: ReactNode
}

export const SelectItem = /* @__PURE__ */ forwardRef<
  ComponentRef<typeof SelectPrimitive.Item>,
  SelectItemProps
>(function SelectItem({ children, className, endContent, ...props }, ref) {
  const styles = /* @__PURE__ */ selectRecipe()

  return (
    <SelectPrimitive.Item ref={ref} className={cx(styles.item, className)} {...props}>
      <SelectPrimitive.ItemIndicator className={styles.itemIndicator}>
        <Check aria-hidden="true" height={14} width={14} />
      </SelectPrimitive.ItemIndicator>
      <SelectPrimitive.ItemText>{children}</SelectPrimitive.ItemText>
      {endContent === undefined ? null : <span className={itemEndClass}>{endContent}</span>}
    </SelectPrimitive.Item>
  )
})
export const SelectLabel = /* @__PURE__ */ forwardRef<
  ComponentRef<typeof SelectPrimitive.Label>,
  ComponentPropsWithoutRef<typeof SelectPrimitive.Label>
>(function SelectLabel({ className, ...props }, ref) {
  const styles = /* @__PURE__ */ selectRecipe()
  return <SelectPrimitive.Label ref={ref} className={cx(styles.label, className)} {...props} />
})
export const SelectSeparator = /* @__PURE__ */ forwardRef<
  ComponentRef<typeof SelectPrimitive.Separator>,
  ComponentPropsWithoutRef<typeof SelectPrimitive.Separator>
>(function SelectSeparator({ className, ...props }, ref) {
  const styles = /* @__PURE__ */ selectRecipe()
  return (
    <SelectPrimitive.Separator ref={ref} className={cx(styles.separator, className)} {...props} />
  )
})
/** A selectable empty value: Radix Select forbids `value=""`, so an option whose
 *  value is the empty string maps to this sentinel internally and back out in
 *  `onValueChange` / the controlled `value`. */
const EMPTY_VALUE = '�stalk-empty'
const toInternal = (value: string) => (value === '' ? EMPTY_VALUE : value)
const fromInternal = (value: string) => (value === EMPTY_VALUE ? '' : value)

export interface SelectOption {
  /** Visible option content. */
  label: ReactNode
  /** Option value. The empty string is allowed and handled via a sentinel. */
  value: string
  disabled?: boolean
}

export interface SelectFieldProps {
  options: readonly SelectOption[]
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  placeholder?: ReactNode
  size?: SelectSize
  /** Stretch the trigger to fill its container; default is content-width. */
  fullWidth?: boolean
  invalid?: boolean
  disabled?: boolean
  name?: string
  required?: boolean
  'aria-label'?: string
  triggerClassName?: string
}

/**
 * Thin first-party convenience over the compound `Select.*` for the common
 * value + onValueChange + options case. Bakes in the empty-value sentinel so an
 * option with `value: ''` is selectable (Radix forbids it natively).
 */
export const SelectField = /* @__PURE__ */ forwardRef<
  ComponentRef<typeof SelectPrimitive.Trigger>,
  SelectFieldProps
>(function SelectField(
  {
    'aria-label': ariaLabel,
    defaultValue,
    disabled = false,
    fullWidth = false,
    invalid = false,
    name,
    onValueChange,
    options,
    placeholder,
    required = false,
    size = 'md',
    triggerClassName,
    value,
  },
  ref,
) {
  return (
    <SelectRoot
      disabled={disabled}
      onValueChange={(next) => onValueChange?.(fromInternal(next))}
      required={required}
      {...(name !== undefined ? { name } : {})}
      {...(value !== undefined ? { value: toInternal(value) } : {})}
      {...(defaultValue !== undefined ? { defaultValue: toInternal(defaultValue) } : {})}
    >
      <SelectTrigger
        ref={ref}
        aria-label={ariaLabel}
        className={triggerClassName}
        fullWidth={fullWidth}
        invalid={invalid}
        size={size}
      >
        <SelectValue placeholder={placeholder} />
      </SelectTrigger>
      <SelectContent>
        {options.map((option) => (
          <SelectItem
            key={option.value}
            disabled={option.disabled ?? false}
            value={toInternal(option.value)}
          >
            {option.label}
          </SelectItem>
        ))}
      </SelectContent>
    </SelectRoot>
  )
})

export const Select = /* @__PURE__ */ Object.assign(SelectRoot, {
  Content: SelectContent,
  Group: SelectGroup,
  Item: SelectItem,
  Label: SelectLabel,
  Portal: SelectPortal,
  Root: SelectRoot,
  Separator: SelectSeparator,
  Trigger: SelectTrigger,
  Value: SelectValue,
})
